mapper.select:
select count(1)
from user_coupon
where user_id = #{userId}
  and coupon_id = #{couponId}

mapper.update:
update user_coupon
set order_id = #{orderId},
    update_time = now()
where id = #{userCouponId}
  and user_id = #{userId}
  and status = 2

update user_coupon
set status = 3,
    use_time = #{useTime},
    update_time = #{updateTime}
where order_id = #{orderId}
  and status = 2

update user_coupon
set status = 3,
    use_time = #{useTime},
    update_time = #{updateTime}
where id = #{userCouponId}
  and status = 2

update user_coupon
set status = 4,
    update_time = #{updateTime}
where user_id = #{userId}
  and status = 1
  and end_time < #{now}

mapper.select:
select uc.*, c.name as coupon_name, c.coupon_type, c.publish_type, c.store_id, c.receive_type, c.status as coupon_status, s.name as store_name from user_coupon uc left join coupon c on uc.coupon_id = c.id left join store s on c.store_id = s.id where uc.user_id = #{userId}
and uc.status = #{status}
and (uc.end_time is null or uc.end_time >= #{now} or uc.status in (3,4))
order by uc.id desc

select uc.id as user_coupon_id, uc.coupon_id, uc.user_id, u.name as user_name, u.username, uc.status, uc.order_id, uc.receive_time, uc.lock_time, uc.use_time, uc.end_time from user_coupon uc left join user u on uc.user_id = u.id where uc.coupon_id = #{couponId}
and uc.status = 3
and uc.status = #{query.userCouponStatus}
and (u.name like concat('%', #{query.userName}, '%') or u.username like concat('%', #{query.userName}, '%'))
order by uc.id desc
